quizDraft.solutionCode:
def divide_numbers(a, b):
    if b == 0:
        return 'Cannot divide by zero'
    return a / b

divide_numbers(10, 2)

def print_variable(var):
    try:
        print(var)
    except NameError:
        print('Variable is not defined')

print_variable('Hello')

